     1→import fs from 'fs';
     2→import matter from 'gray-matter';
     3→import path from 'path';
     4→import rehypePrettyCode from 'rehype-pretty-code';
     5→import rehypeStringify from 'rehype-stringify';
     6→import remarkGfm from 'remark-gfm';
     7→import remarkParse from 'remark-parse';
     8→import remarkRehype from 'remark-rehype';
     9→import { unified } from 'unified';
    10→
    11→const CONTENT_DIR = path.join(process.cwd(), 'content');
    12→const BLOG_CONTENT_DIR = path.join(CONTENT_DIR, 'blog');
    13→const DRAFT_DIRECTORY_NAMES = new Set(['drafts', '_drafts']);
    14→
    15→function rehypeMermaid() {
    16→  return (tree: any) => {
    17→    function walk(node: any) {
    18→      if (node.children) {
    19→        for (const child of node.children) {
    20→          if (
    21→            child.type === 'element' &&
    22→            child.tagName === 'pre' &&
    23→            child.children?.length === 1 &&
    24→            child.children[0].tagName === 'code'
    25→          ) {
    26→            const code = child.children[0];
    27→            const className = (code.properties?.className as string[]) || [];
    28→            if (className.includes('language-mermaid')) {
    29→              const text = code.children[0]?.value || '';
    30→              child.properties = { className: ['mermaid'] };
    31→              child.children = [{ type: 'text', value: text }];
    32→            }
    33→          }
    34→          walk(child);
    35→        }
    36→      }
    37→    }
    38→    walk(tree);
    39→  };
    40→}
    41→
    42→export type Category = 'thoughts' | 'research' | 'economics' | 'philosophy' | 'investing';
    43→
    44→export type Metadata = {
    45→  title: string;
    46→  publishedAt: string;
    47→  summary: string;
    48→  image?: string;
    49→  category?: Category;
    50→  slug?: string;
    51→  draft?: boolean;
    52→  status?: string;
    53→};
    54→
    55→type PostIndexEntry = {
    56→  slug: string;
    57→  filePath: string;
    58→};
    59→
    60→function getMDXFiles(dir: string): string[] {
    61→  if (!fs.existsSync(dir)) {
    62→    return [];
    63→  }
    64→
    65→  return fs.readdirSync(dir, { withFileTypes: true }).flatMap((entry) => {
    66→    const fullPath = path.join(dir, entry.name);
    67→
    68→    if (entry.isDirectory()) {
    69→      return getMDXFiles(fullPath);
    70→    }
    71→
    72→    if (entry.isFile() && path.extname(entry.name) === '.mdx') {
    73→      return [fullPath];
    74→    }
    75→
    76→    return [];
    77→  });
    78→}
    79→
    80→function getLegacyRootMDXFiles(): string[] {
    81→  if (!fs.existsSync(CONTENT_DIR)) {
    82→    return [];
    83→  }
    84→
    85→  return fs
    86→    .readdirSync(CONTENT_DIR, { withFileTypes: true })
    87→    .filter((entry) => entry.isFile() && path.extname(entry.name) === '.mdx')
    88→    .map((entry) => path.join(CONTENT_DIR, entry.name));
    89→}
    90→
    91→function getBlogMDXFiles(): string[] {
    92→  return [...getLegacyRootMDXFiles(), ...getMDXFiles(BLOG_CONTENT_DIR)];
    93→}
    94→
    95→function normalizeSlug(slug: string): string {
    96→  return slug.trim().replace(/^\/+|\/+$/g, '');
    97→}
    98→
    99→function isDraftPath(filePath: string): boolean {
   100→  const relativePath = path.relative(CONTENT_DIR, filePath);
   101→  const segments = relativePath.split(path.sep).map((segment) => segment.toLowerCase());
   102→  return segments.some((segment) => DRAFT_DIRECTORY_NAMES.has(segment));
   103→}
   104→
   105→function isDraftPost(metadata: Metadata, filePath: string): boolean {
   106→  if (isDraftPath(filePath)) {
   107→    return true;
   108→  }
   109→
   110→  if (metadata.draft === true) {
   111→    return true;
   112→  }
   113→
   114→  if (typeof metadata.status === 'string' && metadata.status.toLowerCase() === 'draft') {
   115→    return true;
   116→  }
   117→
   118→  return false;
   119→}
   120→
   121→function resolveSlug(filePath: string, metadata: Metadata): string {
   122→  const fallbackSlug = path.basename(filePath, path.extname(filePath));
   123→  const configuredSlug =
   124→    typeof metadata.slug === 'string' && metadata.slug.length > 0
   125→      ? metadata.slug
   126→      : fallbackSlug;
   127→  const slug = normalizeSlug(configuredSlug);
   128→
   129→  if (!slug) {
   130→    throw new Error(`Empty slug found in ${path.relative(process.cwd(), filePath)}`);
   131→  }
   132→
   133→  if (slug.includes('/')) {
   134→    throw new Error(
   135→      `Invalid slug "${slug}" in ${path.relative(process.cwd(), filePath)}. Nested slugs are not supported with /blog/[slug].`
   136→    );
   137→  }
   138→
   139→  return slug;
   140→}
   141→
   142→function getPostIndex(includeDrafts = false): PostIndexEntry[] {
   143→  const mdxFiles = getBlogMDXFiles();
   144→  const slugToPath = new Map<string, string>();
   145→  const entries: PostIndexEntry[] = [];
   146→
   147→  for (const filePath of mdxFiles) {
   148→    const source = fs.readFileSync(filePath, 'utf-8');
   149→    const { data } = matter(source);
   150→    const metadata = data as Metadata;
   151→
   152→    if (!includeDrafts && isDraftPost(metadata, filePath)) {
   153→      continue;
   154→    }
   155→
   156→    const slug = resolveSlug(filePath, metadata);
   157→    const existingPath = slugToPath.get(slug);
   158→
   159→    if (existingPath) {
   160→      throw new Error(
   161→        `Duplicate slug "${slug}" found in ${path.relative(process.cwd(), existingPath)} and ${path.relative(process.cwd(), filePath)}`
   162→      );
   163→    }
   164→
   165→    slugToPath.set(slug, filePath);
   166→    entries.push({ slug, filePath });
   167→  }
   168→
   169→  return entries;
   170→}
   171→
   172→function generateId(text: string): string {
   173→  return text
   174→    .toLowerCase()
   175→    .replace(/[^\w\s\u4e00-\u9fff-]/g, '')
   176→    .replace(/\s+/g, '-');
   177→}
   178→
   179→function addHeadingIds(html: string): string {
   180→  return html.replace(
   181→    /<(h[1-6])>([^<]+)<\/h[1-6]>/g,
   182→    (_, tag, content) => {
   183→      const id = generateId(content);
   184→      return `<${tag} id="${id}">${content}</${tag}>`;
   185→    }
   186→  );
   187→}
   188→
   189→export async function markdownToHTML(markdown: string) {
   190→  const p = await unified()
   191→    .use(remarkParse)
   192→    .use(remarkGfm)
   193→    .use(remarkRehype)
   194→    .use(rehypeMermaid)
   195→    .use(rehypePrettyCode, {
   196→      // https://rehype-pretty.pages.dev/#usage
   197→      theme: {
   198→        light: 'min-light',
   199→        dark: 'min-dark'
   200→      },
   201→      keepBackground: false
   202→    })
   203→    .use(rehypeStringify)
   204→    .process(markdown);
   205→
   206→  return addHeadingIds(p.toString());
   207→}
   208→
   209→export type TocItem = {
   210→  id: string;
   211→  text: string;
   212→  level: number;
   213→};
   214→
   215→function extractToc(markdown: string): TocItem[] {
   216→  const headingRegex = /^(#{1,6})\s+(.+)$/gm;
   217→  const toc: TocItem[] = [];
   218→  let match;
   219→
   220→  while ((match = headingRegex.exec(markdown)) !== null) {
   221→    const level = match[1].length;
   222→    const text = match[2].trim();
   223→    const id = text
   224→      .toLowerCase()
   225→      .replace(/[^\w\s\u4e00-\u9fff-]/g, '')
   226→      .replace(/\s+/g, '-');
   227→    toc.push({ id, text, level });
   228→  }
   229→
   230→  return toc;
   231→}
   232→
   233→async function parsePostFile(filePath: string, slug: string) {
   234→  let source = fs.readFileSync(filePath, 'utf-8');
   235→  const { content: rawContent, data: metadata } = matter(source);
   236→  const content = await markdownToHTML(rawContent);
   237→  const toc = extractToc(rawContent);
   238→  return {
   239→    source: content,
   240→    metadata: metadata as Metadata,
   241→    slug,
   242→    toc
   243→  };
   244→}
   245→
   246→export async function getPost(slug: string) {
   247→  const normalizedSlug = normalizeSlug(slug);
   248→  const entry = getPostIndex().find((post) => post.slug === normalizedSlug);
   249→
   250→  if (!entry) {
   251→    return null;
   252→  }
   253→
   254→  return parsePostFile(entry.filePath, entry.slug);
   255→}
   256→
   257→async function getAllPosts() {
   258→  const postIndex = getPostIndex();
   259→
   260→  return Promise.all(
   261→    postIndex.map(async ({ slug, filePath }) => {
   262→      let { metadata, source } = await parsePostFile(filePath, slug);
   263→      return {
   264→        metadata: metadata as Metadata,
   265→        slug,
   266→        source
   267→      };
   268→    })
   269→  );
   270→}
   271→
   272→export async function getBlogPosts() {
   273→  return getAllPosts();
   274→}
   275→

