              <p className='text-xs text-muted-foreground leading-relaxed line-clamp-2'>
                {project.description}
              </p>
            </div>
          </Link>
        ))}
      </div>

      {filtered.length === 0 && (
        <p className='text-sm text-muted-foreground'>No projects in this category yet.</p>
      )}
    </section>
  );
}

