  const [error, setError] = useState(false);

  if (!project.logoUrl || error) {
    return (
      <div
        className='w-full aspect-square rounded-lg flex items-center justify-center text-white font-bold text-base'
        style={{ backgroundColor: project.color }}>
        {project.initial}
